"use client";

import { useState, useEffect } from "react";
import { siteConfig } from "@/content/content";
import { Menu, X, Moon, Sun } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useTheme } from "next-themes";
import { toast } from "sonner";

const navLinks = [
    { label: "Home", href: "#home" },
    { label: "Projects", href: "#projects" },
    { label: "Skills", href: "#skills" },
    { label: "Experience", href: "#experience" },
    { label: "About", href: "#about" },
    { label: "Contact", href: "#contact" },
];

const funnyQuotes = [
    "Dark mode developers are judging you right now.",
    "Switching CSS variables from --dark-soul to --holy-sunlight.",
    "Rendering in 10,000 lumens per second."
];

export default function Header() {
    const [isScrolled, setIsScrolled] = useState(false);
    const [mobileOpen, setMobileOpen] = useState(false);
    const [activeSection, setActiveSection] = useState("home");
    const { theme, setTheme } = useTheme();
    const [mounted, setMounted] = useState(false);
    const [quoteIndex, setQuoteIndex] = useState(0);

    useEffect(() => {
        setMounted(true);
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 50);
        };
        window.addEventListener("scroll", handleScroll, { passive: true });
        return () => window.removeEventListener("scroll", handleScroll);
    }, []);

    const toggleTheme = () => {
        if (theme === "dark") {
            setTheme("light");
            toast(funnyQuotes[quoteIndex], {
                icon: 'ΓÿÇ∩╕Å',
                duration: 3000,
            });
            // Loop quote index
            setQuoteIndex((prev) => (prev + 1) % funnyQuotes.length);
        } else {
            setTheme("dark");
        }
    };

    // IntersectionObserver for active section
    useEffect(() => {
        const sections = navLinks.map((l) => l.href.slice(1));
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        setActiveSection(entry.target.id);
                    }
                });
            },
            { rootMargin: "-40% 0px -60% 0px" }
        );

        sections.forEach((id) => {
            const el = document.getElementById(id);
            if (el) observer.observe(el);
        });

        return () => observer.disconnect();
    }, []);

    return (
        <header
            className={`fixed top-0 left-0 right-0 z-[90] transition-all duration-300 will-change-transform transform-gpu ${isScrolled
                ? "bg-white/80 dark:bg-[#050505]/80 backdrop-blur-md shadow-sm border-b border-orange-200/50 dark:border-warm-800/50"
                : "bg-transparent"
                }`}
        >
            <nav className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex items-center justify-between h-16">
                {/* Logo / Name */}
                <a
                    href="#home"
                    className="font-bold text-lg tracking-tight text-orange-500 dark:text-white hover:text-orange-600 dark:hover:text-warm-200 transition-colors w-[200px]"
                >
                    {siteConfig.name}
                </a>

                {/* Desktop Nav - Centered Pill */}
                <div className="hidden md:flex items-center gap-1 bg-orange-50/80 dark:bg-black/40 backdrop-blur-md rounded-full px-1.5 py-1.5 border border-orange-200/50 dark:border-white/5">
                    {navLinks.map((link) => (
                        <a
                            key={link.href}
                            href={link.href}
                            className={`px-4 py-1.5 text-sm font-medium rounded-full transition-all duration-300 ${activeSection === link.href.slice(1)
                                ? "bg-orange-500/10 dark:bg-white/10 text-orange-600 dark:text-white"
                                : "text-orange-400 dark:text-neutral-400 hover:text-orange-600 dark:hover:text-white"
                                }`}
                        >
                            {link.label}
                        </a>
                    ))}
                </div>

                {/* Right side - Theme Toggle & Mobile Menu */}
                <div className="flex items-center justify-end w-[200px]">
                    {mounted && (
                        <button
                            onClick={toggleTheme}
                            className="p-2 text-orange-400 dark:text-neutral-400 hover:text-orange-600 dark:hover:text-white transition-colors hidden md:block"
                            aria-label="Toggle theme"
                        >
                            {theme === "dark" ? <Sun size={18} /> : <Moon size={18} />}
                        </button>
                    )}

                    {/* Mobile Toggle */}
                    <button
                        className="md:hidden p-2 text-orange-500 dark:text-warm-300 hover:text-orange-600 dark:hover:text-warm-50"
                        onClick={() => setMobileOpen(!mobileOpen)}
                        aria-label={mobileOpen ? "Close menu" : "Open menu"}
                    >
                        {mobileOpen ? <X size={22} /> : <Menu size={22} />}
                    </button>
                </div>
            </nav>

            {/* Mobile Menu */}
            <AnimatePresence>
                {mobileOpen && (
                    <motion.div
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        transition={{ duration: 0.2 }}
                        className="md:hidden bg-white/95 dark:bg-black/95 backdrop-blur-md border-b border-orange-200/50 dark:border-white/10 shadow-lg"
                    >
                        <div className="px-4 py-4 space-y-1">
                            {navLinks.map((link) => (
                                <a
                                    key={link.href}
                                    href={link.href}
                                    onClick={() => setMobileOpen(false)}
                                    className={`block px-4 py-2.5 text-sm rounded-lg transition-colors ${activeSection === link.href.slice(1)
                                        ? "bg-orange-500/10 dark:bg-white/10 text-orange-600 dark:text-white font-medium"
                                        : "text-orange-400 dark:text-neutral-400 hover:text-orange-600 dark:hover:text-white"
                                        }`}
                                >
                                    {link.label}
                                </a>
                            ))}
                            <div className="pt-2 mt-2 border-t border-white/10">
                                {mounted && (
                                    <button
                                        onClick={() => {
                                            toggleTheme();
                                            setMobileOpen(false);
                                        }}
                                        className="flex items-center gap-2 px-4 py-2 text-sm text-orange-400 dark:text-neutral-400 hover:text-orange-600 dark:hover:text-white w-full"
                                    >
                                        {theme === "dark" ? <Sun size={16} /> : <Moon size={16} />}
                                        <span>Toggle Theme</span>
                                    </button>
                                )}
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </header>
    );
}

"use client";

import { useRef } from "react";
import { motion, useInView } from "framer-motion";

interface SectionWrapperProps {
    id: string;
    children: React.ReactNode;
    className?: string;
    dark?: boolean;
}

export default function SectionWrapper({
    id,
    children,
    className = "",
    dark = false,
}: SectionWrapperProps) {
    const ref = useRef(null);
    const isInView = useInView(ref, { once: true, margin: "-100px" });

    return (
        <section
            id={id}
            ref={ref}
            className={`section-padding relative w-full ${className}`}
        >
            <motion.div
                initial={{ opacity: 0, y: 40 }}
                animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 40 }}
                transition={{ duration: 0.6, ease: "easeOut" }}
                className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8"
            >
                {children}
            </motion.div>
        </section>
    );
}

"use client";
import { useState } from "react";
import { Loader2, Zap } from "lucide-react";

export function ApiDemo() {
    const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");
    const [data, setData] = useState<any>(null);

    const fetchData = async () => {
        setStatus("loading");
        try {
            const res = await fetch("https://api.github.com/users/torvalds");
            if (!res.ok) throw new Error("Fetch failed");
            const json = await res.json();

            // Simulate slight network delay for visual effect
            setTimeout(() => {
                setData(json);
                setStatus("success");
            }, 800);
        } catch (e) {
            setStatus("error");
            setTimeout(() => setStatus("idle"), 2000);
        }
    };

    return (
        <div className="relative w-full h-56 md:h-64 rounded-2xl border border-neutral-800 bg-[#050505] shadow-sm flex flex-col p-4 overflow-hidden">

            <div className="flex-1 flex flex-col items-center justify-center w-full">
                {status === "idle" && (
                    <button
                        onClick={fetchData}
                        className="group flex items-center gap-2 px-6 py-3 bg-warm-900 text-white rounded-xl text-sm font-medium hover:bg-warm-800 transition-all hover:shadow-lg active:scale-95 border border-transparent hover:border-warm-700 bg-clip-padding"
                    >
                        <Zap size={18} className="text-accent group-hover:scale-110 transition-transform" />
                        Fetch Profile
                    </button>
                )}

                {status === "loading" && (
                    <div className="flex flex-col items-center gap-4 text-warm-500">
                        <div className="w-12 h-12 rounded-xl bg-[#0a0a0a] shadow-sm border border-warm-100 flex items-center justify-center">
                            <Loader2 className="animate-spin text-accent" size={24} />
                        </div>
                        <span className="text-xs font-mono animate-pulse bg-warm-200/50 px-2 py-1 rounded text-warm-600">await fetch('/api/user')...</span>
                    </div>
                )}

                {status === "error" && (
                    <div className="text-sm font-medium text-red-500 bg-red-50 px-3 py-2 rounded-lg border border-red-100">
                        Failed to fetch data.
                    </div>
                )}

                {status === "success" && data && (
                    <div className="flex items-center gap-4 bg-[#0a0a0a] p-4 rounded-2xl border border-neutral-800 shadow-md w-full max-w-[260px] animate-in fade-in slide-in-from-bottom-4 zoom-in-95 duration-500 group relative overflow-hidden">
                        {/* Decorative background accent */}
                        <div className="absolute top-0 right-0 w-24 h-24 bg-accent/5 rounded-bl-full pointer-events-none transition-transform group-hover:scale-110" />

                        {/* eslint-disable-next-line @next/next/no-img-element */}
                        <img src={data.avatar_url} alt="Avatar" className="w-14 h-14 rounded-full ring-2 ring-accent/20 object-cover relative z-10" crossOrigin="anonymous" />

                        <div className="relative z-10 flex-1 min-w-0">
                            <h4 className="text-sm font-bold text-accent leading-tight truncate">{data.name}</h4>
                            <p className="text-xs text-warm-500 font-mono mt-0.5 truncate">@{data.login}</p>
                            <div className="flex items-center gap-2 mt-2">
                                <span className="text-[10px] bg-accent/10 border border-accent/20 text-accent px-2 py-0.5 rounded-full font-medium inline-block">
                                    {data.public_repos} repos
                                </span>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            <div className="absolute bottom-4 left-5 right-5 flex justify-between items-center text-xs font-mono text-warm-400 z-20">
                <span>fetch()</span>
                <span className="px-2 py-1 rounded bg-[#0a0a0a] border border-neutral-800 font-sans font-medium text-[10px] uppercase tracking-wider text-warm-700 shadow-sm">API</span>
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Terminal, Database as DBIcon, TableProperties } from "lucide-react";

export function DatabaseDemo() {
    const [stage, setStage] = useState<"querying" | "results">("querying");

    useEffect(() => {
        const flow = () => {
            setStage("querying");
            setTimeout(() => setStage("results"), 2500);
        };

        flow();
        const interval = setInterval(flow, 5500);
        return () => clearInterval(interval);
    }, []);

    const rows = [
        { id: 1, name: "Project Alpha", status: "Active" },
        { id: 2, name: "Beta Release", status: "Done" },
        { id: 3, name: "DB Migration", status: "Pending" },
    ];

    return (
        <div className="relative w-full h-56 md:h-64 rounded-2xl border border-neutral-800 bg-[#050505] border border-transparent shadow-sm flex flex-col p-4 overflow-hidden">

            {/* Grid background pattern */}
            <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(#0ea5e9 1px, transparent 1px)', backgroundSize: '16px 16px' }} />

            <div className="flex-1 flex flex-col w-full max-w-[280px] mx-auto relative mt-2 z-10">

                {/* Query Input */}
                <div className="bg-slate-900 rounded-lg p-3 shadow-md border border-slate-800 w-full mb-4">
                    <div className="flex gap-1.5 mb-2">
                        <div className="w-2.5 h-2.5 rounded-full bg-red-500/80" />
                        <div className="w-2.5 h-2.5 rounded-full bg-amber-500/80" />
                        <div className="w-2.5 h-2.5 rounded-full bg-emerald-500/80" />
                    </div>
                    <div className="text-[11px] font-mono leading-relaxed">
                        <span className="text-sky-400 font-semibold">SELECT</span> <span className="text-white">*</span> <span className="text-sky-400 font-semibold">FROM</span> <span className="text-cyan-200">projects</span><br />
                        <span className="text-sky-400 font-semibold">WHERE</span> <span className="text-white">status</span> = <span className="text-amber-300">'Active'</span>;
                        {stage === "querying" && <span className="animate-pulse w-1.5 h-3 ml-1 bg-[#0a0a0a] inline-block align-middle" />}
                    </div>
                </div>

                {/* Results Table Visualization */}
                <div className="flex-1 relative">
                    <AnimatePresence>
                        {stage === "results" && (
                            <motion.div
                                initial={{ opacity: 0, y: 15 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -10 }}
                                className="absolute inset-0 bg-[#0a0a0a] rounded-xl border border-sky-100 shadow-sm overflow-hidden flex flex-col"
                            >
                                <div className="bg-sky-50 px-3 py-2 border-b border-sky-100 flex items-center gap-2">
                                    <TableProperties size={12} className="text-sky-600" />
                                    <span className="text-[10px] font-semibold text-sky-800 uppercase tracking-wider">Results (3ms)</span>
                                </div>
                                <div className="flex-1 p-2 flex flex-col gap-1.5">
                                    {rows.map((row, i) => (
                                        <motion.div
                                            key={row.id}
                                            initial={{ opacity: 0, x: -10 }}
                                            animate={{ opacity: 1, x: 0 }}
                                            transition={{ delay: 0.1 + (i * 0.1) }}
                                            className="flex items-center justify-between px-2 py-1.5 rounded-md bg-slate-50 text-[10px] font-mono border border-slate-100"
                                        >
                                            <span className="text-slate-500 w-4">{row.id}</span>
                                            <span className="text-slate-700 flex-1 ml-2 font-sans font-medium">{row.name}</span>
                                            <span className={`px-1.5 py-0.5 rounded-sm ${row.status === 'Active' ? 'bg-emerald-100 text-emerald-700' : row.status === 'Done' ? 'bg-slate-200 text-slate-600' : 'bg-amber-100 text-amber-700'}`}>
                                                {row.status}
                                            </span>
                                        </motion.div>
                                    ))}
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>

            </div>

            <div className="absolute bottom-4 left-5 right-5 flex justify-between items-center text-xs font-mono text-sky-600 z-20">
                <span>pool.query()</span>
                <span className="px-2 py-1 rounded bg-[#0a0a0a] border border-sky-200 font-sans font-medium text-[10px] uppercase tracking-wider text-sky-700 shadow-sm">PostgreSQL</span>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Zap, Activity, Users } from "lucide-react";

export function FastApiDemo() {
    const [isBursting, setIsBursting] = useState(false);
    const [requests, setRequests] = useState<number[]>([]);

    const triggerBurst = () => {
        if (isBursting) return;
        setIsBursting(true);

        // Generate 15 simultaneous requests
        const reqs = Array.from({ length: 15 }, (_, i) => i);
        setRequests(reqs);

        // Clear them very quickly (simulating async/await speed)
        setTimeout(() => {
            setRequests([]);
            setIsBursting(false);
        }, 1800);
    };

    // Auto trigger occasionally if idle
    useEffect(() => {
        const interval = setInterval(() => {
            if (Math.random() > 0.6 && !isBursting) {
                triggerBurst();
            }
        }, 4000);
        return () => clearInterval(interval);
    }, [isBursting]);

    return (
        <div className="relative overflow-hidden w-full h-[320px] rounded-2xl bg-[#050505] border border-transparent flex flex-col p-6 group cursor-pointer" onClick={triggerBurst}>
            <div className="flex items-center gap-3 mb-6 relative z-10 pointer-events-none">
                <div className="w-10 h-10 rounded-xl bg-[#009688] text-white flex items-center justify-center shadow-[0_0_15px_rgba(0,150,136,0.3)]">
                    <Zap size={20} fill="currentColor" />
                </div>
                <div>
                    <h3 className="font-bold text-white group-hover:text-[#009688] transition-colors">FastAPI</h3>
                    <p className="text-sm text-slate-400 font-medium">Asynchronous Python</p>
                </div>
            </div>

            <div className="flex-1 flex flex-col justify-center relative z-10 w-full pointer-events-none">

                <div className="flex justify-between items-center mb-8 px-2 max-w-[280px] w-full mx-auto">
                    {/* Users / Incoming */}
                    <div className="flex flex-col items-center gap-2">
                        <div className="w-12 h-12 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-slate-300 relative">
                            <Users size={20} />
                            <AnimatePresence>
                                {isBursting && (
                                    <motion.div
                                        initial={{ scale: 1, opacity: 1 }}
                                        animate={{ scale: 1.5, opacity: 0 }}
                                        transition={{ duration: 0.5 }}
                                        className="absolute inset-0 border-2 border-slate-400 rounded-full"
                                    />
                                )}
                            </AnimatePresence>
                        </div>
                        <span className="text-[10px] uppercase font-bold text-slate-500">Clients</span>
                    </div>

                    {/* Server Node */}
                    <div className="flex flex-col items-center gap-2">
                        <motion.div
                            className={`w-14 h-14 rounded-xl flex items-center justify-center border-2 z-10 transition-colors ${isBursting ? "bg-[#009688] border-[#80cbc4] text-white shadow-[0_0_30px_rgba(0,150,136,0.5)]" : "bg-slate-800 border-slate-700 text-slate-400"
                                }`}
                            animate={{ scale: isBursting ? [1, 1.1, 1.05] : 1 }}
                        >
                            <Activity className={isBursting ? "animate-pulse" : ""} size={24} />
                        </motion.div>
                        <span className="text-[10px] uppercase font-bold text-[#009688]">ASGI Server</span>
                    </div>
                </div>

                {/* Animated Connectors/Requests */}
                <div className="absolute top-1/2 left-12 right-20 h-16 -translate-y-[4rem] pointer-events-none">
                    <AnimatePresence>
                        {requests.map((id, index) => {
                            // Stagger start times slightly for burst effect
                            const delay = Math.random() * 0.3;
                            const yOffset = (Math.random() - 0.5) * 40; // Spread vertically

                            return (
                                <motion.div
                                    key={id}
                                    initial={{ opacity: 0, x: 0, y: yOffset, scale: 0 }}
                                    animate={{ opacity: [0, 1, 1, 0], x: "180%", scale: [0.5, 1, 0.5] }}
                                    exit={{ opacity: 0 }}
                                    transition={{ duration: 0.6, delay, ease: "easeOut" }}
                                    className="absolute left-8 top-1/2 w-4 h-1.5 bg-[#4db6ac] rounded-full shadow-[0_0_10px_rgba(77,182,172,0.8)]"
                                />
                            );
                        })}
                    </AnimatePresence>
                </div>

                {/* Hint */}
                <div className="absolute bottom-0 w-full text-center">
                    <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">
                        {isBursting ? "Handling 100k+ Req/Sec" : "Click to burst traffic"}
                    </span>
                </div>
            </div>

            <div className="absolute -left-8 -bottom-8 opacity-[0.03] pointer-events-none group-hover:scale-110 transition-transform duration-700">
                <Zap size={180} />
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Sparkles, Image as ImageIcon, Text, Check, Play } from "lucide-react";

export function GeminiDemo() {
    const [generating, setGenerating] = useState(false);
    const [result, setResult] = useState<string | null>(null);

    const runInference = () => {
        if (generating) return;
        setGenerating(true);
        setResult(null);

        // Simulate multi-modal generation delay
        setTimeout(() => {
            setGenerating(false);
            setResult("A majestic golden retriever sitting happily in a sunny field of daisies.");
        }, 2500);
    };

    return (
        <div className="relative overflow-hidden w-full h-[320px] rounded-2xl bg-[#050505] border border-transparent shadow-sm flex flex-col p-6 group">
            <div className="flex items-center gap-3 mb-4 relative z-10">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-r from-blue-500 via-indigo-500 to-purple-500 text-white flex items-center justify-center shadow-[0_0_20px_rgba(99,102,241,0.4)]">
                    <Sparkles size={20} />
                </div>
                <div>
                    <h3 className="font-bold text-white">Google Gemini</h3>
                    <p className="text-sm text-indigo-300 font-medium">Multimodal AI</p>
                </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center relative z-10 w-full">

                {/* Input Area */}
                <div className="w-full flex gap-3 mb-4">
                    {/* Image Modality */}
                    <div className="flex-1 bg-[#151a26] border border-[#2a3045] rounded-xl p-3 flex flex-col items-center justify-center gap-2 relative overflow-hidden">
                        <ImageIcon className="text-indigo-400" size={24} />
                        <span className="text-[10px] uppercase tracking-wider font-bold text-indigo-500">Image Data</span>
                        <div className="absolute inset-0 bg-gradient-to-tr from-indigo-500/10 to-purple-500/10 opacity-50" />
                    </div>

                    {/* Plus */}
                    <div className="flex items-center justify-center text-[#2a3045] font-bold text-xl">
                        +
                    </div>

                    {/* Text Modality */}
                    <div className="flex-1 bg-[#151a26] border border-[#2a3045] rounded-xl p-3 flex flex-col items-center justify-center gap-2 relative overflow-hidden">
                        <Text className="text-purple-400" size={24} />
                        <span className="text-[10px] uppercase tracking-wider font-bold text-purple-500">Prompt</span>
                        <div className="absolute inset-0 bg-gradient-to-br from-blue-500/10 to-indigo-500/10 opacity-50" />
                    </div>
                </div>

                {/* Generate Button / Progress */}
                <div className="w-full flex justify-center mb-4">
                    <motion.button
                        onClick={runInference}
                        disabled={generating || result !== null}
                        className={`px-6 py-2 rounded-full font-bold text-sm tracking-wide transition-all shadow-lg flex items-center gap-2 ${result ? "bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 font-bold" :
                            "bg-[#0a0a0a] text-indigo-900 hover:scale-105 active:scale-95"
                            }`}
                        animate={{
                            width: generating ? "100%" : result ? "140px" : "140px",
                            opacity: generating ? 0.8 : 1
                        }}
                    >
                        {generating ? (
                            <div className="flex items-center gap-2 mx-auto">
                                <Sparkles size={14} className="animate-pulse" /> Generating...
                            </div>
                        ) : result ? (
                            <>
                                <Check size={16} /> Complete
                            </>
                        ) : (
                            <>
                                <Play size={14} fill="currentColor" /> Generate
                            </>
                        )}
                    </motion.button>
                </div>

                {/* Output Area (Streaming Simulation) */}
                <div className="w-full h-20 bg-[#121621] border border-[#1e2333] rounded-xl p-3 relative overflow-hidden">
                    <AnimatePresence>
                        {generating && !result && (
                            <motion.div
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                exit={{ opacity: 0 }}
                                className="absolute inset-0 flex items-center px-4"
                            >
                                <motion.div
                                    className="h-1 bg-gradient-to-r from-blue-500 via-purple-500 to-indigo-500 rounded-full w-full"
                                    initial={{ scaleX: 0, x: "-100%" }}
                                    animate={{ scaleX: 1, x: "100%" }}
                                    transition={{ duration: 1.5, repeat: Infinity, ease: "linear" }}
                                />
                            </motion.div>
                        )}
                        {result && (
                            <motion.div
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="text-sm text-indigo-100 font-medium leading-relaxed italic"
                            >
                                "{result}"
                                <button
                                    onClick={(e) => { e.stopPropagation(); setResult(null); }}
                                    className="block mt-1 text-[10px] text-indigo-400 hover:text-white uppercase tracking-wider not-italic"
                                >
                                    Reset
                                </button>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>
            </div>

            <div className="absolute top-0 right-0 p-8 opacity-[0.1] pointer-events-none group-hover:scale-110 transition-transform duration-1000 origin-top-right mix-blend-screen">
                <Sparkles size={200} className="text-indigo-500" />
            </div>
        </div>
    );
}

