"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Bot, User, Send, CheckCircle2 } from "lucide-react";

const sampleResponse = "Here is a quick overview of OpenAI's capabilities. It excels at natural language understanding, reasoning, and complex generation tasks.";

export function OpenAIDemo() {
    const [state, setState] = useState<"idle" | "typing_user" | "waiting" | "streaming" | "done">("idle");
    const [displayedText, setDisplayedText] = useState("");
    const [charIndex, setCharIndex] = useState(0);

    const startChat = () => {
        if (state !== "idle") return;
        setState("typing_user");
        setDisplayedText("");
        setCharIndex(0);

        setTimeout(() => setState("waiting"), 1000);
    };

    // Streaming effect
    useEffect(() => {
        if (state === "streaming") {
            if (charIndex < sampleResponse.length) {
                const timer = setTimeout(() => {
                    setDisplayedText(prev => prev + sampleResponse[charIndex]);
                    setCharIndex(prev => prev + 1);
                }, 30); // 30ms per char
                return () => clearTimeout(timer);
            } else {
                setState("done");
            }
        }
    }, [state, charIndex]);

    useEffect(() => {
        if (state === "waiting") {
            const timer = setTimeout(() => setState("streaming"), 600);
            return () => clearTimeout(timer);
        }
    }, [state]);

    return (
        <div className="relative overflow-hidden w-full h-[320px] rounded-2xl bg-[#050505] border border-transparent shadow-sm flex flex-col p-6 group">
            <div className="flex items-center gap-3 mb-4 relative z-10">
                <div className="w-10 h-10 rounded-xl bg-emerald-100 text-emerald-600 flex items-center justify-center shadow-sm">
                    <Bot size={22} />
                </div>
                <div>
                    <h3 className="font-bold text-accent group-hover:text-emerald-600 transition-colors">OpenAI</h3>
                    <p className="text-sm text-warm-500 font-medium">LLMs & Streaming</p>
                </div>
            </div>

            <div className="flex-1 flex flex-col relative z-10 w-full bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">

                {/* Chat window */}
                <div className="flex-1 p-3 flex flex-col gap-3 overflow-hidden">

                    {/* User Message */}
                    <AnimatePresence>
                        {(state !== "idle") && (
                            <motion.div
                                initial={{ opacity: 0, y: 10, scale: 0.95 }}
                                animate={{ opacity: 1, y: 0, scale: 1 }}
                                className="flex gap-2 items-end self-end max-w-[85%]"
                            >
                                <div className="bg-emerald-500 text-white p-2 rounded-2xl rounded-br-sm text-xs shadow-sm">
                                    {state === "typing_user" ? (
                                        <div className="flex gap-1 h-4 items-center px-1">
                                            <motion.div animate={{ y: [0, -3, 0] }} transition={{ repeat: Infinity, delay: 0 }} className="w-1.5 h-1.5 bg-[#0a0a0a]/70 rounded-full" />
                                            <motion.div animate={{ y: [0, -3, 0] }} transition={{ repeat: Infinity, delay: 0.2 }} className="w-1.5 h-1.5 bg-[#0a0a0a]/70 rounded-full" />
                                            <motion.div animate={{ y: [0, -3, 0] }} transition={{ repeat: Infinity, delay: 0.4 }} className="w-1.5 h-1.5 bg-[#0a0a0a]/70 rounded-full" />
                                        </div>
                                    ) : (
                                        "Explain OpenAI briefly."
                                    )}
                                </div>
                                <div className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center shrink-0">
                                    <User size={12} className="text-slate-500" />
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {/* AI Message */}
                    <AnimatePresence>
                        {(state === "waiting" || state === "streaming" || state === "done") && (
                            <motion.div
                                initial={{ opacity: 0, y: 10, scale: 0.95 }}
                                animate={{ opacity: 1, y: 0, scale: 1 }}
                                className="flex gap-2 items-start max-w-[90%]"
                            >
                                <div className="w-6 h-6 rounded-full bg-emerald-100 flex items-center justify-center shrink-0 mt-1">
                                    <Bot size={12} className="text-emerald-600" />
                                </div>
                                <div className="bg-[#0a0a0a] border border-slate-200 text-slate-700 p-2.5 rounded-2xl rounded-tl-sm text-xs shadow-sm leading-relaxed min-h-[36px]">
                                    {state === "waiting" ? (
                                        <div className="flex gap-1 h-4 items-center px-1">
                                            <motion.div animate={{ opacity: [0.3, 1, 0.3] }} transition={{ repeat: Infinity, duration: 1 }} className="w-1.5 h-1.5 bg-slate-400 rounded-full" />
                                        </div>
                                    ) : (
                                        <span>
                                            {displayedText}
                                            {state === "streaming" && (
                                                <motion.span
                                                    animate={{ opacity: [1, 0, 1] }}
                                                    transition={{ repeat: Infinity, duration: 0.8 }}
                                                    className="inline-block w-1.5 h-3 bg-emerald-400 ml-0.5 align-middle"
                                                />
                                            )}
                                        </span>
                                    )}
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>

                {/* Input action */}
                <div className="p-2 bg-[#0a0a0a] border-t border-slate-200">
                    <button
                        onClick={startChat}
                        disabled={state !== "idle" && state !== "done"}
                        className="w-full h-8 bg-slate-100 hover:bg-slate-200 text-slate-500 rounded-lg flex items-center justify-between px-3 text-xs font-medium transition-colors disabled:opacity-50 group/btn"
                    >
                        <span>{state === "done" ? "Restart Chat" : "Send Prompt"}</span>
                        {state === "done" ? <CheckCircle2 size={14} className="text-emerald-500" /> : <Send size={12} className="group-hover/btn:translate-x-1 transition-transform" />}
                    </button>
                </div>
            </div>

            <div className="absolute -right-4 -bottom-4 opacity-[0.03] pointer-events-none group-hover:scale-110 transition-transform duration-700">
                <Bot size={140} />
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Search, Database, Bot, ArrowRight, Sparkles } from "lucide-react";

export function RagDemo() {
    const [step, setStep] = useState<"idle" | "searching" | "retrieving" | "generating" | "done">("idle");
    const [query, setQuery] = useState("");

    const handleSearch = () => {
        if (step !== "idle" && step !== "done") return;
        setQuery("What are the latest GenAI trends?");
        setStep("searching");

        setTimeout(() => setStep("retrieving"), 1200);
        setTimeout(() => setStep("generating"), 2500);
        setTimeout(() => setStep("done"), 4500);
    };

    return (
        <div className="relative w-full h-56 md:h-64 rounded-2xl border border-neutral-800 bg-[#050505] from-indigo-50/30 to-purple-50/30 flex flex-col p-4 overflow-hidden shadow-sm group cursor-pointer" onClick={handleSearch}>

            <div className="flex-1 flex flex-col w-full max-w-[280px] mx-auto relative mt-2">

                {/* Search Bar */}
                <motion.div
                    layout
                    className={`w-full bg-[#0a0a0a] rounded-full border shadow-sm flex items-center px-4 py-2.5 transition-colors ${step === "idle" ? "border-neutral-800 group-hover:border-indigo-300" : "border-indigo-200"}`}
                >
                    <Search size={16} className={step === "idle" ? "text-warm-400" : "text-indigo-500"} />
                    <span className={`ml-3 text-sm font-medium ${query ? "text-warm-800" : "text-warm-400"}`}>
                        {query || "Ask AI a question..."}
                    </span>
                    {step === "idle" && <span className="ml-auto text-[10px] font-mono bg-warm-100 text-warm-500 px-2 py-0.5 rounded-md hidden sm:block">Click to run</span>}
                </motion.div>

                <div className="flex-1 mt-4 relative">
                    {/* Pipeline Visualization */}
                    <AnimatePresence>
                        {step !== "idle" && (
                            <div className="absolute inset-0 flex flex-col">

                                {/* Vector DB Step */}
                                <motion.div
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    className="flex items-start gap-3"
                                >
                                    <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 border transition-colors duration-500 ${step === "searching" || step === "retrieving" ? "bg-indigo-100 border-indigo-200 text-indigo-600" : "bg-warm-100 border-neutral-800 text-warm-400"}`}>
                                        <Database size={14} className={step === "searching" ? "animate-pulse" : ""} />
                                    </div>
                                    <div className="flex-1 mt-1.5">
                                        <div className="text-xs font-semibold text-warm-700">Vector Database</div>
                                        <div className="text-[10px] font-mono text-warm-500 mt-1 h-4">
                                            {step === "searching" && <span className="animate-pulse">Searching embeddings...</span>}
                                            {(step === "retrieving" || step === "generating" || step === "done") && <span className="text-emerald-600">Retrieved 3 context docs</span>}
                                        </div>
                                    </div>
                                </motion.div>

                                {/* Connecting Line */}
                                <motion.div
                                    initial={{ height: 0 }}
                                    animate={{ height: 16 }}
                                    transition={{ delay: 1 }}
                                    className="w-px bg-indigo-200 ml-4 my-1"
                                />

                                {/* LLM Generation Step */}
                                {(step === "retrieving" || step === "generating" || step === "done") && (
                                    <motion.div
                                        initial={{ opacity: 0, y: 10 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        className="flex items-start gap-3"
                                    >
                                        <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 border transition-colors duration-500 ${step === "generating" ? "bg-purple-100 border-purple-200 text-purple-600" : step === "done" ? "bg-warm-100 border-neutral-800 text-warm-400" : "bg-warm-50 border-warm-100 text-warm-300"}`}>
                                            <Bot size={14} className={step === "generating" ? "animate-pulse" : ""} />
                                        </div>
                                        <div className="flex-1 bg-[#0a0a0a] p-3 rounded-xl border border-neutral-800 shadow-sm mt-0.5">
                                            {step === "generating" && (
                                                <div className="flex gap-1 items-center h-4">
                                                    <span className="w-1.5 h-1.5 rounded-full bg-purple-400 animate-bounce" />
                                                    <span className="w-1.5 h-1.5 rounded-full bg-purple-400 animate-bounce" style={{ animationDelay: "0.2s" }} />
                                                    <span className="w-1.5 h-1.5 rounded-full bg-purple-400 animate-bounce" style={{ animationDelay: "0.4s" }} />
                                                </div>
                                            )}
                                            {step === "done" && (
                                                <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-[11px] leading-relaxed font-medium text-warm-800">
                                                    <Sparkles size={10} className="inline mr-1 text-purple-500 -mt-0.5" />
                                                    Multi-modal agents and real-time reasoning models are leading...
                                                </motion.p>
                                            )}
                                        </div>
                                    </motion.div>
                                )}
                            </div>
                        )}
                    </AnimatePresence>
                </div>
            </div>

            <div className="absolute bottom-4 left-5 right-5 flex justify-between items-center text-xs font-mono text-indigo-400 z-20">
                <span>context.py</span>
                <span className="px-2 py-1 rounded bg-indigo-50/80 border border-indigo-100 font-sans font-medium text-[10px] uppercase tracking-wider text-indigo-700">RAG</span>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { CheckCircle2, AlertCircle } from "lucide-react";

export function TypeScriptDemo() {
    const [typing, setTyping] = useState<"initial" | "typing" | "error" | "fixing" | "success">("initial");

    useEffect(() => {
        if (typing === "initial") {
            const timer = setTimeout(() => setTyping("typing"), 800);
            return () => clearTimeout(timer);
        }
        if (typing === "typing") {
            const timer = setTimeout(() => setTyping("error"), 1200);
            return () => clearTimeout(timer);
        }
        if (typing === "error") {
            const timer = setTimeout(() => setTyping("fixing"), 2000);
            return () => clearTimeout(timer);
        }
        if (typing === "fixing") {
